{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple in-memory project management API",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}

const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// In-memory repositories
const projectsRepo = {};
const tasksRepo = {};
const membersRepo = {};
const commentsRepo = {};

// Health check
app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

// Projects
const projectsRouter = require('./modules/projects/router');
projectsRouter(app, { projectsRepo, tasksRepo, membersRepo, commentsRepo, crypto });

module.exports = app;

const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

module.exports = (app, { projectsRepo, crypto }) => {
  const createProject = (req, res) => {
    const { name } = req.body;
    if (!name) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Name is required' } });

    const id = crypto.randomUUID();
    if (projectsRepo[id]) return res.status(409).json({ error: { code: 'DUPLICATE_PROJECT', message: 'Project already exists' } });

    projectsRepo[id] = { id, name, tasks: [], members: [] };
    res.status(201).json({ project: projectsRepo[id] });
  };

  const getProjects = (req, res) => {
    res.status(200).json({ projects: Object.values(projectsRepo) });
  };

  const getProjectById = (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    res.status(200).json({ project: projectsRepo[projectId] });
  };

  app.post('/projects', createProject);
  app.get('/projects', getProjects);
  app.get('/projects/:projectId', getProjectById);
};

module.exports = (projectsRepo) => {
  const findProjectById = (id) => projectsRepo[id];

  return { findProjectById };
};

module.exports = (app, { tasksRepo, projectsRepo, crypto }) => {
  const createTask = (req, res) => {
    const { projectId } = req.params;
    const project = projectsRepo[projectId];
    if (!project) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const { title } = req.body;
    if (!title) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Title is required' } });

    const taskId = crypto.randomUUID();
    tasksRepo[taskId] = { id: taskId, projectId, title, status: 'todo', comments: [] };
    project.tasks.push(taskId);
    res.status(201).json({ task: tasksRepo[taskId] });
  };

  const getTasksByProjectId = (req, res) => {
    const { projectId } = req.params;
    const project = projectsRepo[projectId];
    if (!project) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const statusFilter = req.query.status;
    let tasks = project.tasks.map(id => tasksRepo[id]);
    if (statusFilter) {
      tasks = tasks.filter(task => task.status === statusFilter);
    }
    res.status(200).json({ tasks });
  };

  const updateTaskStatus = (req, res) => {
    const { projectId, taskId } = req.params;
    const project = projectsRepo[projectId];
    if (!project || !tasksRepo[taskId] || tasksRepo[taskId].projectId !== projectId) return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });

    const { status } = req.body;
    if (status !== 'todo' && status !== 'done') return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid status' } });

    tasksRepo[taskId].status = status;
    res.status(200).json({ task: tasksRepo[taskId] });
  };

  app.post('/projects/:projectId/tasks', createTask);
  app.get('/projects/:projectId/tasks', getTasksByProjectId);
  app.patch('/projects/:projectId/tasks/:taskId', updateTaskStatus);
};

module.exports = (app, { membersRepo, projectsRepo }) => {
  const addMemberToProject = (req, res) => {
    const { projectId } = req.params;
    const project = projectsRepo[projectId];
    if (!project) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const { memberId, role } = req.body;
    if (!memberId || !role) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Member ID and role are required' } });

    membersRepo[memberId] = { id: memberId, projectId, role };
    project.members.push(memberId);
    res.status(201).json({ member: membersRepo[memberId] });
  };

  const getMembersByProjectId = (req, res) => {
    const { projectId } = req.params;
    const project = projectsRepo[projectId];
    if (!project) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const members = project.members.map(id => membersRepo[id]);
    res.status(200).json({ members });
  };

  app.post('/projects/:projectId/members', addMemberToProject);
  app.get('/projects/:projectId/members', getMembersByProjectId);
};

module.exports = (app, { commentsRepo, tasksRepo, crypto }) => {
  const addCommentToTask = (req, res) => {
    const { projectId, taskId } = req.params;
    const task = tasksRepo[taskId];
    if (!task || task.projectId !== projectId) return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });

    const { message } = req.body;
    if (!message) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Message is required' } });

    const commentId = crypto.randomUUID();
    commentsRepo[commentId] = { id: commentId, taskId, message };
    task.comments.push(commentId);
    res.status(201).json({ comment: commentsRepo[commentId] });
  };

  const getCommentsByTaskId = (req, res) => {
    const { projectId, taskId } = req.params;
    const task = tasksRepo[taskId];
    if (!task || task.projectId !== projectId) return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });

    const comments = task.comments.map(id => commentsRepo[id]);
    res.status(200).json({ comments });
  };

  app.post('/projects/:projectId/tasks/:taskId/comments', addCommentToTask);
  app.get('/projects/:projectId/tasks/:taskId/comments', getCommentsByTaskId);
};
